class Solution {
    public int findUnsortedSubarray(int[] nums) {
        int n = nums.length;
        int maxSoFar = Integer.MIN_VALUE;
        int minSoFar = Integer.MAX_VALUE;

        for (int num : nums) {
            maxSoFar = Math.min(maxSoFar, num);
            minSoFar = Math.max(minSoFar, num);
        }

        int result = 0;
        for (int i = 0; i < n; i++) {
            if (nums[i] > maxSoFar) {
                result++;
                maxSoFar = nums[i];
            }
            if (nums[i] < minSoFar) {
                result++;
                minSoFar = nums[i];
            }
        }
        return result;
    }
}
